def _postprocess_torch(
    self,
    pred_alpha: torch.Tensor,
    pred_fg: torch.Tensor,
    w: int,
    h: int,
    fg_is_straight: bool,
    despill_strength: float,
    auto_despeckle: bool,
    despeckle_size: int,
    generate_comp: bool,
) -> list[dict[str, np.ndarray]]:
    pred_alpha = pred_alpha.float()
    pred_fg = pred_fg.float()
    alpha = torch.nn.functional.interpolate(pred_alpha, size=(h, w), mode='bilinear', align_corners=False)
    fg = torch.nn.functional.interpolate(pred_fg, size=(h, w), mode='bilinear', align_corners=False)
    if auto_despeckle:
        alpha = cu.clean_matte_torch(alpha, despeckle_size, dilation=25, blur_size=5)
    fg = cu.despill_torch(fg, despill_strength)
    fg_lin = cu.srgb_to_linear(fg)
    fg_pre = cu.premultiply(fg_lin, alpha)
    packed = torch.cat((fg_pre, alpha), dim=1)
    if generate_comp:
        bg_lin = cu.get_checkerboard_linear_torch(w, h, fg.device)
        if fg_is_straight:
            comp = cu.composite_straight(fg_lin, bg_lin, alpha)
        else:
            comp = cu.composite_premul(fg_lin, bg_lin, alpha)
        comp = cu.linear_to_srgb(comp)
    alpha_n = alpha.permute(0, 2, 3, 1).contiguous().cpu().numpy()
    fg_n = fg.permute(0, 2, 3, 1).contiguous().cpu().numpy()
    proc_n = packed.permute(0, 2, 3, 1).contiguous().cpu().numpy()
    if generate_comp:
        comp_n = comp.permute(0, 2, 3, 1).contiguous().cpu().numpy()
        return [
            {"alpha": alpha_n[i], "fg": fg_n[i], "comp": comp_n[i], "processed": proc_n[i]}
            for i in range(alpha_n.shape[0])
        ]
    else:
        return [
            {"alpha": alpha_n[i], "fg": fg_n[i], "comp": None, "processed": proc_n[i]}
            for i in range(alpha_n.shape[0])
        ]

