import numpy as np
import threading
import atexit

_capture_cache = {}
_capture_state = {}
_cache_lock = threading.Lock()
_inv255 = np.float32(1.0/255.0)

def _release_caps():
    for cap in _capture_cache.values():
        try: cap.release()
        except: pass
atexit.register(_release_caps)

def read_video_mask_at(video_path: str, frame_index: int) -> np.ndarray | None:
    if frame_index < 0:
        logger.warning("Invalid frame_index %d (must be >= 0)", frame_index)
        return None
    with _cache_lock:
        cap = _capture_cache.get(video_path)
        if cap is None or not cap.isOpened():
            cap = cv2.VideoCapture(video_path)
            _capture_cache[video_path] = cap
            _capture_state[video_path] = -1
        last = _capture_state[video_path]
        if frame_index != last + 1:
            cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index)
    ret, frame = cap.read()
    if not ret:
        return None
    _capture_state[video_path] = frame_index
    return frame[:, :, 2].astype(np.float32) * _inv255

import threading
import cv2
import numpy as np
from logging import getLogger

logger = getLogger(__name__)
_CAP_CACHE: dict[str, tuple[cv2.VideoCapture, int]] = {}
_CACHE_LOCK = threading.Lock()
_SKIP_THRESHOLD = 16

def read_video_frame_at(video_path: str, frame_index: int) -> np.ndarray | None:
    if frame_index < 0:
        logger.warning("Invalid frame_index %d (must be >= 0)", frame_index)
        return None
    with _CACHE_LOCK:
        entry = _CAP_CACHE.get(video_path)
        if entry is None:
            cap = cv2.VideoCapture(video_path)
            if not cap.isOpened():
                logger.warning("Could not open video: %s", video_path)
                return None
            last_idx = 0
            _CAP_CACHE[video_path] = (cap, last_idx)
        else:
            cap, last_idx = entry
    delta = frame_index - last_idx
    if delta >= 0 and delta <= _SKIP_THRESHOLD:
        for _ in range(delta):
            if not cap.grab():
                logger.warning("Could not seek to frame %d in %s", frame_index, video_path)
                return None
        ret, frame = cap.retrieve()
    else:
        if not cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index):
            logger.warning("Could not set frame position %d for %s", frame_index, video_path)
            return None
        ret, frame = cap.read()
    if not ret or frame is None:
        logger.warning("Could not read video frame %d from: %s", frame_index, video_path)
        return None
    with _CACHE_LOCK:
        _CAP_CACHE[video_path] = (cap, frame_index + 1)
    return frame[..., ::-1].astype(np.float32) * (1.0 / 255.0)

def _ensure_torch_checkpoint() -> Path:
    dest = Path(CHECKPOINT_DIR) / HF_CHECKPOINT_FILENAME
    hf_url = f"https://huggingface.co/{HF_REPO_ID}"
    from huggingface_hub import hf_hub_download
    logger.info("Downloading CorridorKey checkpoint from %s ...", hf_url)
    try:
        cached_path = hf_hub_download(
            repo_id=HF_REPO_ID,
            filename=HF_CHECKPOINT_FILENAME,
        )
    except Exception as exc:
        raise RuntimeError(
            f"Failed to download CorridorKey checkpoint from {hf_url}. "
            "Check your network connection and try again. "
            f"Original error: {exc}"
        ) from exc
    dest.parent.mkdir(parents=True, exist_ok=True)
    try:
        shutil.copy2(cached_path, dest)
    except OSError as exc:
        if exc.errno == errno.ENOSPC:
            raise OSError(
                errno.ENOSPC,
                f"Not enough disk space to save checkpoint (~300 MB required). "
                f"Free up space in {CHECKPOINT_DIR} and try again."
            ) from exc
        raise
    logger.info("Checkpoint saved to %s", dest)
    return dest

