def _discover_checkpoint(ext: str) -> Path:
    dir_path = Path(CHECKPOINT_DIR)
    other_ext = MLX_EXT if ext == TORCH_EXT else TORCH_EXT
    matches = []
    other_found = False
    for entry in dir_path.iterdir():
        if not entry.is_file():
            continue
        suffix = entry.suffix
        if suffix == ext:
            matches.append(entry)
        elif suffix == other_ext:
            other_found = True
    if not matches:
        if ext == TORCH_EXT:
            return _ensure_torch_checkpoint()
        hint = (f" (Found {other_ext} files — did you mean --backend="
                f"{'mlx' if other_ext == MLX_EXT else 'torch'}?)") if other_found else ""
        raise FileNotFoundError(f"No {ext} checkpoint found in {CHECKPOINT_DIR}.{hint}")
    if len(matches) > 1:
        names = [entry.name for entry in matches]
        raise ValueError(f"Multiple {ext} checkpoints in {CHECKPOINT_DIR}: {names}. Keep exactly one.")
    return matches[0]

