    dialect = storage.adapter.get_dialect()
    adapter = storage.adapter
    driver = storage.driver

    try:
        if driver is None:
            raise RuntimeError("Driver not initialized")
        num = driver.schema.version.read()
        if num is None:
            num = 0
    except Exception:
        if self._requires_rollback(dialect) and adapter is not None:
