def read_video_mask_at(
    video_path: str,
    frame_index: int,
) -> np.ndarray | None:
    if not hasattr(read_video_mask_at, "_cache"):
        from collections import OrderedDict
        import atexit
        import cv2

        class VideoCaptureCache:
            def __init__(self, capacity: int = 16):
                self.cache = OrderedDict()
                self.capacity = capacity
                atexit.register(self.cleanup)

            def get(self, path: str):
                if path in self.cache:
                    self.cache.move_to_end(path)
                    return self.cache[path]

                cap = cv2.VideoCapture(path)
                if not cap.isOpened():
                    cap.release()
                    return None

                if len(self.cache) >= self.capacity:
                    _, old_cap = self.cache.popitem(last=False)
                    old_cap.release()

                self.cache[path] = cap
                return cap

            def cleanup(self):
                for cap in self.cache.values():
                    cap.release()
                self.cache.clear()

        read_video_mask_at._cache = VideoCaptureCache()

    if frame_index < 0:
        logger.warning("Invalid frame_index %d (must be >= 0)", frame_index)
        return None

    cap = read_video_mask_at._cache.get(video_path)

    if cap is None:
        return None

    try:
        if not cap.set(cv2.CAP_PROP_POS_FRAMES, frame_index):
            return None

        ret, frame = cap.read()
        if not ret or frame is None:
            return None

        return frame[:, :, 2].astype(np.float32) / 255.0
    except cv2.error:
        return None

