def create_data_structures(self):
    if self.display_banner:
        self.cli.banner()

    storage = self.config.storage
    if not storage or not storage.adapter:
        return self

    adapter = storage.adapter
    driver = storage.driver
    dialect = adapter.get_dialect()

    if not driver:
        raise RuntimeError("Driver not initialized")

    try:
        current_revision = driver.schema.version.read() or 0
    except Exception:
        if self._requires_rollback(dialect):
            adapter.rollback()
        current_revision = 0

    self.cli.notice(f"Currently at revision #{current_revision}.")

    migrations = self._get_dialect_family(dialect)
    if not migrations:
        raise NotImplementedError(f"No migration mapping found for dialect: {dialect}.")

    all_revisions = sorted(migrations.keys())
    if not all_revisions or current_revision >= all_revisions[-1]:
        self.cli.notice("Data structures are up-to-date.", 1)
    else:
        revisions_to_apply = [rev for rev in all_revisions if rev > current_revision]

        try:
            for revision_num in revisions_to_apply:
                self.cli.notice(f"Building revision #{revision_num}...")
                for migration in migrations[revision_num]:
                    self.cli.notice(migration["description"], 1)
                    operation = migration.get("operations") or migration.get("operation")
                    if operation:
                        adapter.execute(operation)

            final_revision = revisions_to_apply[-1]
            driver.schema.version.delete()
            driver.schema.version.create(final_revision)

            adapter.commit()
        except Exception as e:
            self.cli.error(f"Migration failed: {e}")
            adapter.rollback()
            raise

    self.cli.notice("Build executed successfully!")
    self.cli.newline()

    return self

