def __init__(self, path: str, asset_type: str) -> None:
    self.path = path
    self.type = asset_type
    if asset_type == 'video':
        try:
            import cv2
            cap = cv2.VideoCapture(path)
            if cap.isOpened():
                frame_count = int(cap.get(cv2.CAP_PROP_FRAME_COUNT))
                cap.release()
                self.frame_count = frame_count
            else:
                self.frame_count = 0
        except Exception:
            self.frame_count = 0
    elif asset_type == 'sequence':
        try:
            import os
            image_extensions = {'.png', '.jpg', '.jpeg', '.bmp', '.tif', '.tiff', '.exr'}
            if os.path.isdir(path):
                self.frame_count = sum(1 for entry in os.scandir(path) if entry.is_file() and os.path.splitext(entry.name)[1].lower() in image_extensions)
            else:
                self.frame_count = 0
        except OSError:
            self.frame_count = 0
    else:
        self.frame_count = 0

