def create_data_structures(self):
    if self.display_banner:
        self.cli.banner()

    storage = self.config.storage
    if not storage or not storage.adapter:
        return self

    adapter = storage.adapter
    dialect = adapter.get_dialect()

    try:
        driver = storage.driver
        if not driver:
            raise RuntimeError("Driver not initialized")
        num = driver.schema.version.read() or 0
    except Exception:
        if self._requires_rollback(dialect):
            adapter.rollback()
        num = 0

    self.cli.notice(f"Currently at revision #{num}.")

    migrations = self._get_dialect_family(dialect)
    if migrations is None:
        raise NotImplementedError(
            f"No migration mapping found for dialect: {dialect}."
        )

    latest_version = max(migrations.keys()) if migrations else 0

    if num >= latest_version:
        self.cli.notice("data structures are up-to-date", 1)
    else:
        pending_versions = sorted(v for v in migrations if v > num)

        try:
            for version in pending_versions:
                self.cli.notice(f"Building revision #{version}...")
                for migration in migrations[version]:
                    self.cli.notice(migration["description"], 1)
                    operation = migration.get("operations") or migration.get("operation")
                    if operation:
                        adapter.execute(operation)

            driver = storage.driver
            if not driver:
                raise RuntimeError("Driver not initialized")

            final_version = pending_versions[-1]
            driver.schema.version.delete()
            driver.schema.version.create(final_version)

            adapter.commit()
        except Exception:
            self.cli.error("Migration failed. Rolling back changes.")
            if self._requires_rollback(dialect):
                adapter.rollback()
            raise

    self.cli.notice("Build executed successfully!")
    self.cli.newline()

    return self

